// === CONFIGURATION - Edit cities here ===
const cities = [
  { name: 'Málaga', lat: 36.72, lon: -4.42, timezone: 'Europe/Madrid' },
  { name: 'Madrid', lat: 40.42, lon: -3.70, timezone: 'Europe/Madrid' },
  { name: 'Faro (Algarve)', lat: 37.02, lon: -7.93, timezone: 'Europe/Lisbon' },
  { name: 'Nice', lat: 43.71, lon: 7.27, timezone: 'Europe/Paris' }
];
// More cities — uncomment or add as needed:
// { name: 'London', lat: 51.51, lon: -0.13, timezone: 'Europe/London' },
// { name: 'Paris', lat: 48.86, lon: 2.35, timezone: 'Europe/Paris' },
// { name: 'Stockholm', lat: 59.33, lon: 18.07, timezone: 'Europe/Stockholm' },
// { name: 'Helsinki', lat: 60.17, lon: 24.94, timezone: 'Europe/Helsinki' },
// { name: 'New York', lat: 40.71, lon: -74.01, timezone: 'America/New_York' },
// { name: 'Barcelona', lat: 41.39, lon: 2.17, timezone: 'Europe/Madrid' },
// { name: 'Lisbon', lat: 38.72, lon: -9.14, timezone: 'Europe/Lisbon' },
// { name: 'Rome', lat: 41.90, lon: 12.50, timezone: 'Europe/Rome' },
// === END CONFIGURATION ===

const allData = [];
const errors = [];

for (const city of cities) {
  try {
    const url = `https://api.open-meteo.com/v1/forecast?latitude=${city.lat}&longitude=${city.lon}&daily=temperature_2m_max,temperature_2m_min,apparent_temperature_max,apparent_temperature_min,precipitation_sum,precipitation_probability_max,wind_speed_10m_max,uv_index_max,weather_code&hourly=temperature_2m,precipitation_probability,weather_code&timezone=${city.timezone}&forecast_days=7`;

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url,
      returnFullResponse: false,
      timeout: 15000
    });

    allData.push({
      city: city.name,
      lat: city.lat,
      lon: city.lon,
      timezone: city.timezone,
      daily: response.daily,
      hourly: response.hourly,
      daily_units: response.daily_units,
      hourly_units: response.hourly_units
    });
  } catch (e) {
    errors.push({ city: city.name, error: e.message || String(e) });
  }
}

const dateLabel = new Date().toISOString().split('T')[0];

return [{ json: {
  dateLabel,
  totalCities: allData.length,
  cities: allData,
  errors,
  generatedAt: new Date().toISOString()
} }];

const data = $input.first().json;

const weatherCodes = {
  0: 'Clear sky', 1: 'Mainly clear', 2: 'Partly cloudy', 3: 'Overcast',
  45: 'Foggy', 48: 'Rime fog', 51: 'Light drizzle', 53: 'Moderate drizzle',
  55: 'Dense drizzle', 61: 'Slight rain', 63: 'Moderate rain', 65: 'Heavy rain',
  71: 'Slight snow', 73: 'Moderate snow', 75: 'Heavy snow',
  80: 'Slight showers', 81: 'Moderate showers', 82: 'Heavy showers',
  95: 'Thunderstorm', 96: 'Thunderstorm + hail', 99: 'Thunderstorm + heavy hail'
};

const weatherSummary = data.cities.map(city => {
  const d = city.daily;
  let s = `### ${city.city}\n`;
  for (let i = 0; i < d.time.length; i++) {
    const wc = weatherCodes[d.weather_code[i]] || 'Unknown';
    s += `${d.time[i]}: ${wc}, ${d.temperature_2m_min[i]}–${d.temperature_2m_max[i]}°C (feels ${d.apparent_temperature_min[i]}–${d.apparent_temperature_max[i]}°C), Rain: ${d.precipitation_probability_max[i]}% (${d.precipitation_sum[i]}mm), Wind: ${d.wind_speed_10m_max[i]} km/h, UV: ${d.uv_index_max[i]}\n`;
  }
  return s;
}).join('\n');

const prompt = `You are a weather analyst writing a morning briefing for someone living in the Mediterranean. Analyze this 7-day forecast data for ${data.totalCities} cities.

WEATHER DATA:
${weatherSummary}

${data.errors.length > 0 ? 'API errors: ' + JSON.stringify(data.errors) : ''}

RULES:
- Write a concise, practical morning briefing
- Use Celsius throughout
- Highlight anything notable: heat waves, storms, high UV, big temperature swings, best/worst days
- Compare cities where useful (e.g. "Madrid significantly hotter than the coast")
- Include outdoor/travel recommendations

FORMAT:

## Overview
2-3 sentences on the overall Mediterranean weather pattern this week.

## Today at a Glance
One bullet per city — what to expect today, practically.

## Week Ahead
Key trends and notable days across all cities. What days are best for outdoor plans? Any weather to watch out for?

## Travel & Outdoor Tips
2-3 practical recommendations.

Output only the markdown.`;

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 2048,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body } }];

const response = $input.first().json;
const markdown = response.content[0].text;
const weatherData = $('Fetch Weather').first().json.cities;

const weatherCodes = {
  0: ['\u2600\ufe0f', 'Clear sky'], 1: ['\ud83c\udf24', 'Mainly clear'],
  2: ['\u26c5', 'Partly cloudy'], 3: ['\u2601\ufe0f', 'Overcast'],
  45: ['\ud83c\udf2b', 'Foggy'], 48: ['\ud83c\udf2b', 'Rime fog'],
  51: ['\ud83c\udf26', 'Light drizzle'], 53: ['\ud83c\udf26', 'Drizzle'],
  55: ['\ud83c\udf27', 'Dense drizzle'], 61: ['\ud83c\udf27', 'Slight rain'],
  63: ['\ud83c\udf27', 'Moderate rain'], 65: ['\ud83c\udf27', 'Heavy rain'],
  71: ['\ud83c\udf28', 'Slight snow'], 73: ['\ud83c\udf28', 'Moderate snow'],
  75: ['\u2744\ufe0f', 'Heavy snow'], 80: ['\ud83c\udf26', 'Slight showers'],
  81: ['\ud83c\udf27', 'Moderate showers'], 82: ['\ud83c\udf27', 'Heavy showers'],
  95: ['\u26c8', 'Thunderstorm'], 96: ['\u26c8', 'Thunder + hail'],
  99: ['\u26c8', 'Thunder + heavy hail']
};

function cToF(c) { return Math.round(c * 9/5 + 32); }

function tempColor(c) {
  if (c <= 0) return '#60a5fa';
  if (c <= 10) return '#38bdf8';
  if (c <= 18) return '#34d399';
  if (c <= 25) return '#fbbf24';
  if (c <= 32) return '#f97316';
  return '#ef4444';
}

// Find global temp range for consistent bar scaling
let globalMin = 100, globalMax = -100;
for (const city of weatherData) {
  for (let i = 0; i < city.daily.time.length; i++) {
    globalMin = Math.min(globalMin, city.daily.temperature_2m_min[i]);
    globalMax = Math.max(globalMax, city.daily.temperature_2m_max[i]);
  }
}
globalMin = Math.floor(globalMin - 3);
globalMax = Math.ceil(globalMax + 3);

// Parse Claude's markdown into HTML
function inlineStyles(text) {
  let s = text;
  s = s.replace(/\*\*(.+?)\*\*/g, '<strong style="color:#e2e8f0;">$1</strong>');
  s = s.replace(/\*(.+?)\*/g, '<em>$1</em>');
  return s;
}

let summaryHtml = '';
const lines = markdown.split('\n');
let inList = false;
for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) {
    if (inList) { summaryHtml += '</table>'; inList = false; }
    continue;
  }
  if (trimmed.startsWith('# ')) continue;
  if (trimmed.startsWith('## ')) {
    if (inList) { summaryHtml += '</table>'; inList = false; }
    summaryHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="padding:16px 0 8px 0; border-top:1px solid #1e3a5f;"><h2 style="color:#93c5fd; font-size:18px; margin:0; font-weight:bold; font-family:Arial,sans-serif;">${trimmed.slice(3)}</h2></td></tr></table>`;
  } else if (trimmed.startsWith('### ')) {
    if (inList) { summaryHtml += '</table>'; inList = false; }
    summaryHtml += `<h3 style="color:#bfdbfe; font-size:15px; margin:12px 0 4px 0; font-weight:bold; font-family:Arial,sans-serif;">${trimmed.slice(4)}</h3>`;
  } else if (trimmed.startsWith('- ')) {
    if (!inList) { summaryHtml += '<table width="100%" cellpadding="0" cellspacing="0" border="0">'; inList = true; }
    const content = inlineStyles(trimmed.slice(2));
    summaryHtml += `<tr><td style="padding:5px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="4" style="background-color:#3b82f6;"></td><td style="padding:8px 12px; background-color:#0f1d32; font-family:Arial,sans-serif; font-size:14px; color:#cbd5e1; line-height:1.5;">${content}</td></tr></table></td></tr>`;
  } else {
    if (inList) { summaryHtml += '</table>'; inList = false; }
    summaryHtml += `<p style="color:#cbd5e1; line-height:1.6; margin:6px 0; font-family:Arial,sans-serif; font-size:14px;">${inlineStyles(trimmed)}</p>`;
  }
}
if (inList) summaryHtml += '</table>';

// Build city weather sections with charts and tables
const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
let citiesHtml = '';

for (const city of weatherData) {
  const daily = city.daily;
  const todayCode = daily.weather_code[0];
  const todayW = weatherCodes[todayCode] || ['\ud83c\udf21', 'Unknown'];
  const todayMax = daily.temperature_2m_max[0];
  const todayMin = daily.temperature_2m_min[0];

  // City header
  citiesHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-top:20px;"><tr><td style="padding:12px 16px; background-color:#1e3a5f; border-left:4px solid #3b82f6;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="font-family:Arial,sans-serif;"><div style="font-size:20px; color:#e2e8f0; font-weight:bold;">${city.city}</div><div style="font-size:14px; color:#93c5fd; margin-top:4px;">Today: ${todayW[0]} ${todayW[1]} | ${todayMax}\u00b0C (${cToF(todayMax)}\u00b0F) / ${todayMin}\u00b0C (${cToF(todayMin)}\u00b0F)</div></td><td width="60" style="text-align:right; font-size:36px;">${todayW[0]}</td></tr></table></td></tr></table>`;

  // Temperature bar chart
  citiesHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-top:4px;"><tr><td style="padding:10px 16px; background-color:#0f1d32;"><div style="font-size:11px; color:#64748b; font-family:Arial,sans-serif; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">7-Day Temperature Range</div><table width="100%" cellpadding="0" cellspacing="0" border="0">`;

  for (let i = 0; i < daily.time.length; i++) {
    const date = new Date(daily.time[i] + 'T00:00:00');
    const dayName = dayNames[date.getDay()];
    const dateStr = `${date.getDate()}/${date.getMonth()+1}`;
    const min = daily.temperature_2m_min[i];
    const max = daily.temperature_2m_max[i];
    const range = globalMax - globalMin;
    const leftPct = Math.round(((min - globalMin) / range) * 100);
    const widthPct = Math.max(4, Math.round(((max - min) / range) * 100));
    const isToday = i === 0;
    const rowBg = isToday ? 'background-color:#1a2744;' : '';
    const labelColor = isToday ? '#93c5fd' : '#94a3b8';
    const labelWeight = isToday ? 'font-weight:bold;' : '';

    citiesHtml += `<tr><td width="65" style="padding:4px 8px 4px 0; font-family:Arial,sans-serif; font-size:12px; color:${labelColor}; ${labelWeight} ${rowBg} white-space:nowrap;">${dayName} ${dateStr}</td><td width="35" style="padding:4px 4px; font-family:Arial,sans-serif; font-size:11px; color:#94a3b8; text-align:right; ${rowBg}">${min}\u00b0</td><td style="padding:4px 0; ${rowBg}"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="${leftPct}%" style="height:14px;"></td><td width="${widthPct}%" style="height:14px; background:linear-gradient(90deg, ${tempColor(min)}, ${tempColor(max)});"></td><td style="height:14px;"></td></tr></table></td><td width="35" style="padding:4px 0 4px 4px; font-family:Arial,sans-serif; font-size:11px; color:#e2e8f0; text-align:left; ${rowBg}">${max}\u00b0</td></tr>`;
  }

  citiesHtml += `</table></td></tr></table>`;

  // Precipitation probability bars
  citiesHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-top:2px;"><tr><td style="padding:10px 16px; background-color:#0f1d32;"><div style="font-size:11px; color:#64748b; font-family:Arial,sans-serif; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">Precipitation Probability</div><table width="100%" cellpadding="0" cellspacing="0" border="0">`;

  for (let i = 0; i < daily.time.length; i++) {
    const date = new Date(daily.time[i] + 'T00:00:00');
    const dayName = dayNames[date.getDay()];
    const rainPct = daily.precipitation_probability_max[i];
    const rainColor = rainPct > 70 ? '#3b82f6' : rainPct > 40 ? '#60a5fa' : rainPct > 10 ? '#93c5fd' : '#1e3a5f';

    citiesHtml += `<tr><td width="40" style="padding:3px 8px 3px 0; font-family:Arial,sans-serif; font-size:11px; color:#94a3b8;">${dayName}</td><td style="padding:3px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="${Math.max(1, rainPct)}%" style="height:10px; background-color:${rainColor};"></td><td style="height:10px;"></td></tr></table></td><td width="36" style="padding:3px 0 3px 8px; font-family:Arial,sans-serif; font-size:11px; color:#94a3b8; text-align:right;">${rainPct}%</td></tr>`;
  }

  citiesHtml += `</table></td></tr></table>`;

  // Detail data table
  citiesHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-top:2px;"><tr><td style="padding:10px 16px 16px 16px; background-color:#0f1d32;"><div style="font-size:11px; color:#64748b; font-family:Arial,sans-serif; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">Detailed Forecast</div><table width="100%" cellpadding="4" cellspacing="0" border="0" style="font-family:Arial,sans-serif; font-size:11px;"><tr style="color:#64748b; text-transform:uppercase; letter-spacing:1px; font-size:10px;"><td style="padding:4px; border-bottom:1px solid #1e3a5f;">Day</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;"></td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">Max</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">Min</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">Feels</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">Rain</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">Precip</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">Wind</td><td style="padding:4px; border-bottom:1px solid #1e3a5f; text-align:center;">UV</td></tr>`;

  for (let i = 0; i < daily.time.length; i++) {
    const date = new Date(daily.time[i] + 'T00:00:00');
    const dayName = dayNames[date.getDay()];
    const wc = daily.weather_code[i];
    const weather = weatherCodes[wc] || ['\ud83c\udf21', '?'];
    const max = daily.temperature_2m_max[i];
    const min = daily.temperature_2m_min[i];
    const feelsMax = daily.apparent_temperature_max[i];
    const isToday = i === 0;
    const rowColor = isToday ? '#e2e8f0' : '#94a3b8';
    const rowWeight = isToday ? 'font-weight:bold;' : '';
    const uvVal = daily.uv_index_max[i];
    const uvColor = uvVal >= 8 ? '#ef4444' : uvVal >= 5 ? '#f97316' : '#94a3b8';

    const uvLabel = uvVal >= 11 ? 'Extreme' : uvVal >= 8 ? 'Very High' : uvVal >= 6 ? 'High' : uvVal >= 3 ? 'Moderate' : 'Low';

    citiesHtml += `<tr><td style="padding:4px; color:${rowColor}; ${rowWeight} white-space:nowrap;">${dayName} ${date.getDate()}/${date.getMonth()+1}</td><td style="padding:4px; text-align:center;" title="${weather[1]}">${weather[0]}</td><td style="padding:4px; color:${tempColor(max)}; text-align:center; ${rowWeight}">${max}\u00b0 (${cToF(max)}\u00b0F)</td><td style="padding:4px; color:${tempColor(min)}; text-align:center;">${min}\u00b0 (${cToF(min)}\u00b0F)</td><td style="padding:4px; color:#94a3b8; text-align:center;">${feelsMax}\u00b0</td><td style="padding:4px; color:#60a5fa; text-align:center;">${daily.precipitation_probability_max[i]}%</td><td style="padding:4px; color:#94a3b8; text-align:center;">${daily.precipitation_sum[i]}mm</td><td style="padding:4px; color:#94a3b8; text-align:center;">${daily.wind_speed_10m_max[i]} km/h</td><td style="padding:4px; color:${uvColor}; text-align:center;">${uvVal} ${uvLabel}</td></tr>`;
  }

  citiesHtml += `</table></td></tr></table>`;
}

// Full email HTML
const dateLabel = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const cityNames = weatherData.map(c => c.city).join(' \u00b7 ');

const html = `<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd"><html xmlns="http://www.w3.org/1999/xhtml"><head><meta http-equiv="Content-Type" content="text/html; charset=utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Weather Forecast</title></head><body style="margin:0; padding:0; background-color:#0a0f1a; -webkit-text-size-adjust:100%;">
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#0a0f1a;"><tr><td align="center" style="padding:0;">
<table width="660" cellpadding="0" cellspacing="0" border="0" style="max-width:660px; width:100%;">
  <!-- Header -->
  <tr><td style="background-color:#1e3a5f; padding:36px 32px 28px 32px; border-bottom:3px solid #3b82f6;">
    <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
      <td style="font-family:Arial,sans-serif;">
        <div style="font-size:12px; color:#93c5fd; text-transform:uppercase; letter-spacing:3px; font-weight:bold; margin-bottom:10px;">\u2600\ufe0f Daily Forecast</div>
        <h1 style="color:#f1f5f9; font-size:26px; margin:0 0 6px 0; font-weight:bold; font-family:Arial,sans-serif;">Weather Forecast</h1>
        <div style="color:#94a3b8; font-size:13px; font-family:Arial,sans-serif;">${dateLabel}</div>
        <div style="color:#64748b; font-size:12px; font-family:Arial,sans-serif; margin-top:4px;">${cityNames}</div>
      </td>
      <td width="80" valign="top" style="text-align:right; font-size:48px;">\ud83c\udf24</td>
    </tr></table>
  </td></tr>
  <!-- Claude Summary -->
  <tr><td style="background-color:#111827; padding:24px 32px;">
    ${summaryHtml}
  </td></tr>
  <!-- Reference Legend -->
  <tr><td style="background-color:#111827; padding:0 32px 16px 32px;">
    <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="padding:12px 16px; background-color:#0f1d32; border-left:4px solid #64748b;">
      <div style="font-size:11px; color:#64748b; font-family:Arial,sans-serif; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">Reading Guide</div>
      <table width="100%" cellpadding="0" cellspacing="0" border="0">
        <tr><td style="padding:4px 0; font-family:Arial,sans-serif; font-size:12px; color:#94a3b8;"><strong style="color:#bfdbfe;">UV Index:</strong> <span style="color:#94a3b8;">0-2 Low</span> \u00b7 <span style="color:#fbbf24;">3-5 Moderate</span> \u00b7 <span style="color:#f97316;">6-7 High</span> \u00b7 <span style="color:#ef4444;">8-10 Very High</span> \u00b7 <span style="color:#dc2626;">11+ Extreme</span></td></tr>
        <tr><td style="padding:4px 0; font-family:Arial,sans-serif; font-size:12px; color:#94a3b8;"><strong style="color:#bfdbfe;">Wind:</strong> <span style="color:#94a3b8;">0-19 Calm/Light</span> \u00b7 <span style="color:#fbbf24;">20-39 Moderate</span> \u00b7 <span style="color:#f97316;">40-61 Strong</span> \u00b7 <span style="color:#ef4444;">62+ Storm</span> <span style="color:#64748b;">(km/h)</span></td></tr>
        <tr><td style="padding:4px 0; font-family:Arial,sans-serif; font-size:12px; color:#94a3b8;"><strong style="color:#bfdbfe;">Weather:</strong> \u2600\ufe0f Clear \u00b7 \ud83c\udf24 Mostly Clear \u00b7 \u26c5 Partly Cloudy \u00b7 \u2601\ufe0f Overcast \u00b7 \ud83c\udf27 Rain \u00b7 \u26c8 Thunderstorm</td></tr>
      </table>
    </td></tr></table>
  </td></tr>
  <!-- City Weather Sections -->
  <tr><td style="background-color:#111827; padding:0 32px 24px 32px;">
    ${citiesHtml}
  </td></tr>
  <!-- Footer -->
  <tr><td style="background-color:#0a0f1a; padding:20px 32px; border-top:1px solid #1e3a5f; text-align:center; font-family:Arial,sans-serif;">
    <div style="color:#3b82f6; font-size:12px; font-weight:bold; letter-spacing:1px;">BOXINOM</div>
    <div style="color:#475569; font-size:11px; margin-top:4px;">Weather Intelligence \u00b7 Published Daily</div>
    <div style="color:#374151; font-size:10px; margin-top:4px;">Data: Open-Meteo API \u00b7 Analysis: Claude AI</div>
  </td></tr>
</table>
</td></tr></table>
</body></html>`;

// Build markdown version
const dateForFile = $('Fetch Weather').first().json.dateLabel;
let md = `# Weather Forecast - ${dateForFile}\n\n`;
md += markdown + '\n\n---\n\n';
for (const city of weatherData) {
  const d = city.daily;
  md += `## ${city.city}\n\n`;
  md += `| Day | Weather | Max\u00b0C (\u00b0F) | Min\u00b0C (\u00b0F) | Feels | Rain% | Precip | Wind | UV |\n`;
  md += `|-----|---------|----------|----------|-------|-------|--------|------|-----|\n`;
  for (let i = 0; i < d.time.length; i++) {
    const date = new Date(d.time[i] + 'T00:00:00');
    const dayName = dayNames[date.getDay()];
    const wc = d.weather_code[i];
    const weather = weatherCodes[wc] || ['?', '?'];
    md += `| ${dayName} ${date.getDate()}/${date.getMonth()+1} | ${weather[0]} ${weather[1]} | ${d.temperature_2m_max[i]}\u00b0 (${cToF(d.temperature_2m_max[i])}\u00b0F) | ${d.temperature_2m_min[i]}\u00b0 (${cToF(d.temperature_2m_min[i])}\u00b0F) | ${d.apparent_temperature_max[i]}\u00b0 | ${d.precipitation_probability_max[i]}% | ${d.precipitation_sum[i]}mm | ${d.wind_speed_10m_max[i]} km/h | ${d.uv_index_max[i]} |\n`;
  }
  md += '\n';
}

const buffer = Buffer.from(md, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, `weather-${dateForFile}.md`, 'text/markdown');

return [{ json: { markdown: md, html }, binary: { data: binaryData } }];
